from flask import Flask, request, jsonify, session
from flask_bcrypt import Bcrypt
import pyotp
import qrcode
from io import BytesIO
import base64
import secrets

app = Flask(__name__)
app.secret_key = secrets.token_hex(16)
bcrypt = Bcrypt(app)

# Mock database
users_db = {
    "user1": {
        "password": "$2b$12$...",
        "mfa_enabled": True,
        "mfa_secret": "JBSWY3DPEHPK3PXP"
    },
    "user2": {
        "password": "$2b$12$...",
        "mfa_enabled": False,
        "mfa_secret": None
    }
}

@app.route('/login', methods=['POST'])
def login():
    data = request.get_json()
    username = data.get('username')
    password = data.get('password')
    api_client = data.get('api_client', False)
    
    user = users_db.get(username)
    if not user or not bcrypt.check_password_hash(user['password'], password):
        return jsonify({"error": "Invalid credentials"}), 401
    
    if api_client:
        session['user'] = username
        session['authenticated'] = True
        return jsonify({"message": "Login successful", "access_token": "token123"})
    
    if user['mfa_enabled']:
        session['pending_mfa'] = username
        return jsonify({"message": "MFA required", "mfa_required": True})
    
    session['user'] = username
    session['authenticated'] = True
    return jsonify({"message": "Login successful", "access_token": "token123"})

@app.route('/verify-otp', methods=['POST'])
def verify_otp():
    if 'pending_mfa' not in session:
        return jsonify({"error": "No pending MFA verification"}), 400
    
    data = request.get_json()
    otp = data.get('otp')
    username = session['pending_mfa']
    
    user = users_db.get(username)
    if not user or not user['mfa_enabled']:
        return jsonify({"error": "MFA not enabled for user"}), 400
    
    totp = pyotp.TOTP(user['mfa_secret'])
    if not totp.verify(otp, valid_window=2):
        return jsonify({"error": "Invalid OTP"}), 401
    
    session['user'] = username
    session['authenticated'] = True
    session.pop('pending_mfa', None)
    return jsonify({"message": "Login successful", "access_token": "token123"})

@app.route('/api/direct-login', methods=['POST'])
def direct_login():
    data = request.get_json()
    username = data.get('username')
    password = data.get('password')
    
    user = users_db.get(username)
    if not user or not bcrypt.check_password_hash(user['password'], password):
        return jsonify({"error": "Invalid credentials"}), 401
    
    session['user'] = username
    session['authenticated'] = True
    return jsonify({"message": "Direct login successful", "access_token": "token123"})

@app.route('/mfa-setup', methods=['GET'])
def mfa_setup():
    if 'user' not in session or not session.get('authenticated'):
        return jsonify({"error": "Unauthorized"}), 401
    
    username = session['user']
    user = users_db.get(username)
    if not user:
        return jsonify({"error": "User not found"}), 404
    
    secret = pyotp.random_base32()
    user['mfa_secret'] = secret
    users_db[username] = user
    
    totp = pyotp.TOTP(secret)
    provisioning_uri = totp.provisioning_uri(username, issuer_name="MyApp")
    
    qr = qrcode.QRCode(version=1, box_size=10, border=4)
    qr.add_data(provisioning_uri)
    qr.make(fit=True)
    
    img = qr.make_image(fill_color="black", back_color="white")
    buffer = BytesIO()
    img.save(buffer, format="PNG")
    buffer.seek(0)
    
    img_str = base64.b64encode(buffer.getvalue()).decode()
    
    return jsonify({
        "secret": secret,
        "qr_code": img_str,
        "provisioning_uri": provisioning_uri
    })

@app.route('/enable-mfa', methods=['POST'])
def enable_mfa():
    if 'user' not in session or not session.get('authenticated'):
        return jsonify({"error": "Unauthorized"}), 401
    
    data = request.get_json()
    otp = data.get('otp')
    
    username = session['user']
    user = users_db.get(username)
    if not user or not user['mfa_secret']:
        return jsonify({"error": "No MFA secret found"}), 400
    
    totp = pyotp.TOTP(user['mfa_secret'])
    if not totp.verify(otp, valid_window=2):
        return jsonify({"error": "Invalid OTP"}), 401
    
    user['mfa_enabled'] = True
    users_db[username] = user
    
    return jsonify({"message": "MFA enabled successfully"})

@app.route('/logout', methods=['POST'])
def logout():
    session.clear()
    return jsonify({"message": "Logged out successfully"})

@app.before_request
def require_auth():
    if request.endpoint and request.endpoint not in ['login', 'direct_login', 'mfa_setup', 'enable_mfa']:
        if 'user' not in session or not session.get('authenticated'):
            return jsonify({"error": "Unauthorized"}), 401

if __name__ == '__main__':
    app.run(debug=True)